import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../../App';
import { STATIONS, GARBAGE_TYPES, AREAS } from '../../data/mockData';
import LiveMap from '../../components/LiveMap';
import { timeAgo } from '../../utils/helpers';
import {
  Camera, MapPin, Send, ChevronLeft, CheckCircle2, AlertTriangle,
  Trash2, Package, FlaskConical, Recycle, Droplets, Clock,
  Navigation, Image, X, Shield, Bell
} from 'lucide-react';

// UI Color Palette from your first code
const C = {
  navy: '#0A1628', blue: '#1565C0', blue2: '#1976D2', blueL: '#E3F2FD',
  green: '#2E7D32', greenL: '#E8F5E9', red: '#B71C1C', redL: '#FFEBEE',
  amber: '#E65100', amberL: '#FFF3E0', gray: '#546E7A', grayL: '#ECEFF1',
  text: '#0D1117', text2: '#3D4F61', text3: '#7A8FA6',
  white: '#fff', surface: '#F7F9FC', border: '#DDE3E9',
};

const GTYPE_ICONS = {
  'Plastic Waste': Trash2, 'Food Waste': Package, 'Abandoned Item': Package,
  'Chemical Spill': FlaskConical, 'Recyclable Waste': Recycle, 'Sewage / Water': Droplets,
};

const StatusBadge = ({ status }) => {
  const map = {
    NEW: { bg: C.amberL, c: C.amber, l: 'Pending' },
    ACCEPTED: { bg: C.blueL, c: C.blue, l: 'Accepted' },
    IN_PROGRESS: { bg: '#EDE7F6', c: '#4527A0', l: 'In Progress' },
    COMPLETED: { bg: C.greenL, c: C.green, l: 'Done' }
  };
  const m = map[status] || map.NEW;
  return <span style={{ background: m.bg, color: m.c, padding: '3px 9px', borderRadius: 99, fontSize: 10.5, fontWeight: 700 }}>{m.l}</span>;
};

export default function UserPortal() {
  const { addComplaint, complaints } = useApp();
  const videoRef = useRef(null);

  // Workflow steps: 'MAP_VIEW' | 'CAMERA_VIEW' | 'FORM_VIEW' | 'SUCCESS_VIEW'
  const [currentStep, setCurrentStep] = useState('MAP_VIEW');

  // Form states from Code 2
  const [capturedImage, setCapturedImage] = useState(null);
  const [gtypeIdx, setGtypeIdx] = useState(0);
  const [stationName, setStationName] = useState(STATIONS[0]?.name || '');
  const [area, setArea] = useState(AREAS[0]);
  const [desc, setDesc] = useState('');
  const [ticketId, setTicketId] = useState(null);
  const [myReports, setMyReports] = useState([]);

  // Nagpur Base Coordinates
  const nagpurBaseLat = 21.1522;
  const nagpurBaseLng = 79.0882;
  const [mapCenter, setMapCenter] = useState({ lat: nagpurBaseLat, lng: nagpurBaseLng });
  const [photoCapturedCoords, setPhotoCapturedCoords] = useState({ lat: null, lng: null });

  const activeComplaints = complaints ? complaints.filter(c => c.lat && c.lng) : [];

  // 1. Initial Overview Map Geo-positioning
  useEffect(() => {
    if (navigator.geolocation && currentStep === 'MAP_VIEW') {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setMapCenter({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        () => console.log("Using default Nagpur Junction view anchor."),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  }, [currentStep]);

  // 2. Camera Stream Manager from Code 2 (Using environment / back camera)
  useEffect(() => {
    let activeStream = null;

    if (currentStep === 'CAMERA_VIEW') {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false })
        .then(stream => {
          activeStream = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
          }
        })
        .catch(err => {
          console.error("Camera access failed: ", err);
          alert('Camera access denied or unavailable. Please allow camera permissions.');
          setCurrentStep('MAP_VIEW');
        });
    }

    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [currentStep]);

  // 3. Instant Snapshot & GPS Capture Logic
  const capturePhoto = () => {
    if (!videoRef.current) return;

    // Capture Canvas Frame
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    const base64Data = canvas.toDataURL('image/jpeg');
    setCapturedImage(base64Data);

    // Get exact GPS coordinates at click moment
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setPhotoCapturedCoords({
            lat: position.coords.latitude.toFixed(5),
            lng: position.coords.longitude.toFixed(5)
          });
        },
        (error) => {
          console.error("GPS snapshot failed. Using Nagpur fallback.", error);
          setPhotoCapturedCoords({ lat: nagpurBaseLat, lng: nagpurBaseLng });
        },
        { enableHighAccuracy: true, timeout: 6000 }
      );
    } else {
      setPhotoCapturedCoords({ lat: nagpurBaseLat, lng: nagpurBaseLng });
    }

    setCurrentStep('FORM_VIEW');
  };

  // 4. Submit Complaint Handler
  const handleFormSubmission = (e) => {
    e.preventDefault();
    const selectedGType = GARBAGE_TYPES[gtypeIdx];

    const id = addComplaint({
      gtype: selectedGType.label,
      emoji: '📷',
      severity: selectedGType.severity || 'normal',
      station: stationName,
      area: area,
      note: desc,
      lat: photoCapturedCoords.lat || nagpurBaseLat,
      lng: photoCapturedCoords.lng || nagpurBaseLng,
      photoURL: capturedImage,
    });

    setTicketId(id);

    // Track local reports state
    setMyReports(prev => [{
      id,
      gtype: selectedGType.label,
      area: area,
      photoURL: capturedImage,
      station: { name: stationName },
      status: 'NEW',
      reportedAt: new Date(),
    }, ...prev]);

    setCurrentStep('SUCCESS_VIEW');
  };

  const resetWorkflow = () => {
    setCapturedImage(null);
    setPhotoCapturedCoords({ lat: null, lng: null });
    setDesc('');
    setCurrentStep('MAP_VIEW');
  };

  return (
    <div style={{ width: '100%', maxWidth: 430, margin: '0 auto', background: C.white, display: 'flex', flexDirection: 'column', height: '100vh', fontFamily: 'DM Sans,system-ui,sans-serif', overflow: 'hidden', border: `1px solid ${C.border}` }}>
      
      {/* ─── SCREEN 1: MAP VIEW (Design from Code 1) ─── */}
      {currentStep === 'MAP_VIEW' && (
        <div style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
          {/* Header */}
          <div style={{ background: `linear-gradient(135deg,${C.navy} 0%,${C.blue} 100%)`, padding: '12px 18px 10px', flexShrink: 0 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
              <div style={{ width: 20, height: 14, borderRadius: 2, overflow: 'hidden', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
                <div style={{ flex: 1, background: '#FF9933' }} /><div style={{ flex: 1, background: '#fff' }} /><div style={{ flex: 1, background: '#138808' }} />
              </div>
              <span style={{ color: 'rgba(255,255,255,.65)', fontSize: 10, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase' }}>Indian Railways · Nagpur Division</span>
            </div>
            <div style={{ color: '#fff', fontSize: 17, fontWeight: 800, marginBottom: 1 }}>Swachh Rail — Nagpur</div>
            <div style={{ color: 'rgba(255,255,255,.55)', fontSize: 11 }}>Report garbage near you · No login needed</div>
          </div>

          {/* Map Container */}
          <div style={{ flex: 1, position: 'relative', minHeight: 200 }}>
            <LiveMap complaints={activeComplaints} center={[mapCenter.lat, mapCenter.lng]} zoom={14} height="100%" />
            
            {/* Action Camera Button */}
            <button onClick={() => setCurrentStep('CAMERA_VIEW')} style={{ position: 'absolute', bottom: 16, left: '50%', transform: 'translateX(-50%)', background: C.blue, color: C.white, padding: '13px 26px', borderRadius: 99, fontWeight: 800, fontSize: 14, border: 'none', cursor: 'pointer', boxShadow: `0 4px 20px ${C.blue}66`, display: 'flex', alignItems: 'center', gap: 8, whiteSpace: 'nowrap', zIndex: 500 }}>
              <Camera size={18} /> Report Garbage
            </button>

            {/* Active Reports Badge */}
            <div style={{ position: 'absolute', top: 10, right: 10, background: 'rgba(10,22,40,.85)', color: '#fff', padding: '5px 12px', borderRadius: 8, fontSize: 11, fontWeight: 600, zIndex: 400, display: 'flex', alignItems: 'center', gap: 5 }}>
              <Shield size={12} color="#42A5F5" /> {activeComplaints.length} active reports
            </div>
          </div>

          {/* User History List */}
          <div style={{ background: C.white, borderTop: `1px solid ${C.border}`, padding: '10px 14px', maxHeight: 185, overflowY: 'auto', flexShrink: 0 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: C.text, marginBottom: 8 }}>Your Reports ({myReports.length})</div>
            {myReports.length === 0 ? (
              <div style={{ fontSize: 12, color: C.text3, textAlign: 'center', padding: '10px 0', display: 'flex', alignItems: 'center', justifyCenter: 'center', gap: 6 }}>
                <MapPin size={13} color={C.text3} /> Tap the button above to make your first report
              </div>
            ) : (
              myReports.map(r => (
                <div key={r.id} style={{ display: 'flex', alignItems: 'center', gap: 9, padding: '7px 0', borderBottom: `1px solid ${C.border}` }}>
                  <div style={{ width: 40, height: 40, borderRadius: 8, overflow: 'hidden', flexShrink: 0, border: `1px solid ${C.border}`, background: C.surface }}>
                    <img src={r.photoURL} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 10, fontFamily: 'monospace', color: C.text3 }}>{r.id}</div>
                    <div style={{ fontSize: 12.5, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{r.gtype} — {r.area}</div>
                    <div style={{ fontSize: 11, color: C.text3, display: 'flex', alignItems: 'center', gap: 4 }}><Clock size={10} /> {timeAgo(r.reportedAt)}</div>
                  </div>
                  <StatusBadge status={r.status} />
                </div>
              ))
            )}
          </div>

          {/* Bottom Tabs Mock */}
          <div style={{ background: C.white, borderTop: `1px solid ${C.border}`, display: 'flex', flexShrink: 0 }}>
            {[{ Icon: MapPin, l: 'Map', on: true }, { Icon: Image, l: 'Reports' }, { Icon: Navigation, l: 'Help' }].map(b => (
              <button key={b.l} style={{ flex: 1, padding: '9px 4px', textAlign: 'center', border: 'none', background: 'none' }}>
                <b.Icon size={19} color={b.on ? C.blue : C.text3} style={{ display: 'block', margin: '0 auto 2px' }} />
                <span style={{ fontSize: 9.5, fontWeight: 700, color: b.on ? C.blue : C.text3 }}>{b.l}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* ─── SCREEN 2: CAMERA VIEW (Camera execution logic from Code 2) ─── */}
      {currentStep === 'CAMERA_VIEW' && (
        <div style={{ display: 'flex', flexDirection: 'column', flex: 1, background: '#000', position: 'relative' }}>
          {/* Header Controls */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 16px', position: 'absolute', top: 0, left: 0, right: 0, zIndex: 10, background: 'linear-gradient(to bottom,rgba(0,0,0,.65),transparent)' }}>
            <button onClick={() => setCurrentStep('MAP_VIEW')} style={{ width: 36, height: 36, borderRadius: '50%', background: 'rgba(0,0,0,.45)', border: 'none', display: 'flex', alignItems: 'center', justifyCenter: 'center', cursor: 'pointer' }}>
              <X size={18} color="#fff" />
            </button>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, background: 'rgba(21,101,192,.85)', padding: '5px 12px', borderRadius: 99 }}>
              <MapPin size={12} color="#fff" />
              <span style={{ fontSize: 11, fontWeight: 600, color: '#fff' }}>Locking GPS Grid...</span>
            </div>
            <div style={{ width: 36 }} />
          </div>

          {/* Viewfinder Window */}
          <div style={{ flex: 1, position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <video ref={videoRef} playsInline autoPlay muted style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            
            {/* Target Camera Framing Corners */}
            {[{ t: 24, l: 24, bw: '3px 0 0 3px', br: '6px 0 0 0' }, { t: 24, r: 24, bw: '3px 3px 0 0', br: '0 6px 0 0' }, { b: 24, l: 24, bw: '0 0 3px 3px', br: '0 0 0 6px' }, { b: 24, r: 24, bw: '0 3px 3px 0', br: '0 0 6px 0' }].map((g, i) => (
              <div key={i} style={{ position: 'absolute', width: 40, height: 40, borderColor: 'rgba(255,255,255,.8)', borderStyle: 'solid', borderWidth:g.bw, borderRadius:g.br, top:g.t, left:g.l, right:g.r, bottom:g.b }} />
            ))}
          </div>

          {/* Shutter Panel Control */}
          <div style={{ background: '#111', padding: '20px 24px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
            <button onClick={capturePhoto} style={{ width: 74, height: 74, borderRadius: '50%', background: C.white, border: '4px solid rgba(255,255,255,.3)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyCenter: 'center', padding: 0 }}>
              <div style={{ width: 56, height: 56, borderRadius: '50%', background: C.white, border: `2px solid ${C.border}` }} />
            </button>
          </div>
        </div>
      )}

      {/* ─── SCREEN 3: COMPLAINT FORM & REPORT DETAIL VIEW ─── */}
      {currentStep === 'FORM_VIEW' && (
        <form onSubmit={handleFormSubmission} style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '11px 16px', borderBottom: `1px solid ${C.border}`, background: C.white, flexShrink: 0 }}>
            <button type="button" onClick={() => setCurrentStep('CAMERA_VIEW')} style={{ width: 34, height: 34, borderRadius: '50%', background: C.surface, border: `1px solid ${C.border}`, display: 'flex', alignItems: 'center', justifyCenter: 'center' }}>
              <ChevronLeft size={18} color={C.text2} />
            </button>
            <span style={{ fontSize: 15, fontWeight: 700, flex: 1, color: C.text }}>Classify & Confirm</span>
          </div>

          <div style={{ flex: 1, overflowY: 'auto' }}>
            {/* Image Preview Banner */}
            <div style={{ position: 'relative', background: '#000', height: 180 }}>
              <img src={capturedImage} alt="garbage snapshot" style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
              <div style={{ position: 'absolute', top: 8, left: 8, background: 'rgba(0,0,0,.65)', color: '#fff', padding: '4px 10px', borderRadius: 99, fontSize: 11, fontWeight: 700 }}>
                📸 Snapshot Recorded
              </div>
            </div>

            <div style={{ padding: '13px 15px' }}>
              {/* GPS Information Box */}
              <div style={{ background: C.greenL, border: '1px solid #C8E6C9', borderRadius: 10, padding: '8px 12px', display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                <MapPin size={15} color={C.green} />
                <div>
                  <div style={{ fontSize: 11.5, fontWeight: 700, color: C.green }}>Location Geotagged — Nagpur</div>
                  <div style={{ fontSize: 10.5, color: C.green, fontFamily: 'monospace' }}>
                    {photoCapturedCoords.lat ? `${photoCapturedCoords.lat}°N, ${photoCapturedCoords.lng}°E` : 'Fetching exact GPS...'}
                  </div>
                </div>
              </div>

              {/* Garbage Category Matrix Dropdown */}
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: C.text3, textTransform: 'uppercase', marginBottom: 5 }}>Select Garbage Type</label>
                <select value={gtypeIdx} onChange={e => setGtypeIdx(parseInt(e.target.value))} style={{ width: '100%', padding: '10px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, background: C.white }}>
                  {GARBAGE_TYPES.map((g, idx) => (
                    <option key={g.id} value={idx}>{g.label} {g.severity === 'critical' ? '(URGENT)' : ''}</option>
                  ))}
                </select>
              </div>

              {/* Station Selection */}
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: C.text3, textTransform: 'uppercase', marginBottom: 5 }}>Nearest Station</label>
                <select value={stationName} onChange={e => setStationName(e.target.value)} style={{ width: '100%', padding: '10px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, background: C.white }}>
                  {STATIONS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                </select>
              </div>

              {/* Exact Area Selection */}
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: C.text3, textTransform: 'uppercase', marginBottom: 5 }}>Exact Area / Platform</label>
                <select value={area} onChange={e => setArea(e.target.value)} style={{ width: '100%', padding: '10px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, background: C.white }}>
                  {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>

              {/* Note Descriptions Text Area */}
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: C.text3, textTransform: 'uppercase', marginBottom: 5 }}>Additional Details</label>
                <textarea value={desc} onChange={e => setDesc(e.target.value)} maxLength={200} placeholder="Describe the issue (e.g. Near exit gate, under bench)..." style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, minHeight: 60, resize: 'none', fontFamily: 'inherit' }} />
              </div>
            </div>
          </div>

          {/* Form Action Footer */}
          <div style={{ padding: '11px 14px 15px', borderTop: `1px solid ${C.border}`, display: 'flex', gap: 9, flexShrink: 0, background: C.white }}>
            <button type="button" onClick={resetWorkflow} style={{ background: C.surface, color: C.text2, padding: '11px 13px', borderRadius: 11, fontSize: 13, fontWeight: 600, border: `1px solid ${C.border}` }}>Cancel</button>
            <button type="submit" style={{ flex: 1, background: C.blue, color: C.white, padding: '12px', borderRadius: 11, fontSize: 14, fontWeight: 800, border: 'none', display: 'flex', alignItems: 'center', justifyCenter: 'center', gap: 7, boxShadow: `0 2px 12px ${C.blue}55` }}>
              <Send size={16} /> File Complaint
            </button>
          </div>
        </form>
      )}

      {/* ─── SCREEN 4: SUCCESS RECEIPT SCREEN ─── */}
      {currentStep === 'SUCCESS_VIEW' && (
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          <div style={{ position: 'relative', flexShrink: 0, background: '#000', height: 160 }}>
            <img src={capturedImage} alt="reported issue" style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', opacity: 0.6 }} />
            <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyCenter: 'center', gap: 6 }}>
              <CheckCircle2 size={44} color="#4CAF50" strokeWidth={2} />
              <div style={{ color: '#fff', fontSize: 19, fontWeight: 800 }}>Complaint Registered!</div>
              <div style={{ color: 'rgba(255,255,255,.7)', fontSize: 12 }}>Cleaning crew dispatched instantly</div>
            </div>
          </div>

          <div style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>
            <div style={{ background: C.navy, color: '#fff', borderRadius: 14, padding: '13px 18px', marginBottom: 14 }}>
              <div style={{ fontSize: 9.5, opacity: 0.5, fontWeight: 700, letterSpacing: 0.5, textTransform: 'uppercase', marginBottom: 2 }}>Ticket Token Reference</div>
              <div style={{ fontSize: 22, fontWeight: 800, fontFamily: 'monospace', letterSpacing: 1 }}>{ticketId || 'SR-99812'}</div>
              <div style={{ fontSize: 11, opacity: 0.6, marginTop: 3 }}>Vendor team has been notified at Nagpur Division.</div>
            </div>

            <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: '11px 13px', marginBottom: 14 }}>
              {[['Target Station', stationName], ['Exact Grid Area', area], ['Status Trigger', 'NEW / PENDING']].map(([k, v]) => (
                <div key={k} style={{ display: 'flex', alignItems: 'center', justifyCenter: 'space-between', padding: '8px 0', borderBottom: `1px solid ${C.border}` }}>
                  <span style={{ fontSize: 12.5, color: C.text2 }}>{k}</span>
                  <span style={{ fontSize: 12.5, fontWeight: 600, color: C.text }}>{v}</span>
                </div>
              ))}
            </div>

            <div style={{ background: C.greenL, border: '1px solid #C8E6C9', borderRadius: 12, padding: '10px 13px', fontSize: 12.5, color: C.green, display: 'flex', gap: 7 }}>
              <Bell size={14} style={{ flexShrink: 0, marginTop: 2 }} /> 
              <span>You will see live marker dashboard status change once our cleaner wraps up the job.</span>
            </div>
          </div>

          <div style={{ padding: '11px 16px 18px', borderTop: `1px solid ${C.border}`, flexShrink: 0, background: C.white }}>
            <button onClick={resetWorkflow} style={{ width: '100%', background: C.blue, color: C.white, padding: '13px', borderRadius: 12, fontSize: 14, fontWeight: 700, border: 'none', display: 'flex', alignItems: 'center', justifyCenter: 'center', gap: 7 }}>
              <MapPin size={16} /> Track on Main Map
            </button>
          </div>
        </div>
      )}

    </div>
  );
}
